$table_warehouse = $this->db->query("SHOW TABLES LIKE '" . DB_PREFIX . "warehouse'");
if (!$table_warehouse->num_rows) {
    $this->db->query("
        CREATE TABLE `" . DB_PREFIX . "warehouse` (
            `warehouse_id` INT(11) NOT NULL AUTO_INCREMENT,
            `name` VARCHAR(255) NOT NULL,
            `address_1` VARCHAR(255) NOT NULL,
            `address_2` VARCHAR(255) NOT NULL,
            `city` VARCHAR(128) NOT NULL,
            `postcode` VARCHAR(10) NOT NULL,
            `country_id` INT NOT NULL,
            `zone_id` INT NOT NULL,
            PRIMARY KEY (`warehouse_id`)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci
    ");
}    

// Add 'date_completed' to warehouse_order
if (!$this->db->query("SHOW COLUMNS FROM " . DB_PREFIX . "warehouse_order LIKE 'date_completed'")->row) {
    $this->db->query("ALTER TABLE `" . DB_PREFIX . "warehouse_order` ADD `date_completed` datetime NULL");
}   

// Add 'partial_weights' to order_product
if (!$this->db->query("SHOW COLUMNS FROM " . DB_PREFIX . "order_product LIKE 'partial_weights'")->row) {
    $this->db->query("ALTER TABLE `" . DB_PREFIX . "order_product` ADD `partial_weights` TEXT NULL AFTER `dc_qty`");
}


