public function __construct($registry) { 

    parent::__construct($registry);

    // Check if the column exists
    $query = $this->db->query("SHOW COLUMNS FROM `" . DB_PREFIX . "user` LIKE 'warehouse_id'");

    // If the column does not exist, add it
    if (!$query->num_rows) {
        $this->db->query("ALTER TABLE `" . DB_PREFIX . "user` ADD `warehouse_id` INT(11) NOT NULL DEFAULT 0, ADD INDEX idx_warehouse_id (warehouse_id)");
    }
}


if (isset($data['delivery_zone_id'])) {
