public function __construct($registry) { 

    parent::__construct($registry);

    // Check if the column exists
    $query = $this->db->query("SHOW COLUMNS FROM `" . DB_PREFIX . "product` LIKE 'warehouse_id'");

    // If the column does not exist, add it
    if (!$query->num_rows) {
        $this->db->query("ALTER TABLE `" . DB_PREFIX . "product` ADD `warehouse_id` INT(11) NOT NULL DEFAULT 0");
    }

    // foreign key constraint
    $query = $this->db->query("SELECT CONSTRAINT_NAME
        FROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE
        WHERE TABLE_NAME = '" . DB_PREFIX . "product'
        AND COLUMN_NAME = 'warehouse_id'
        AND CONSTRAINT_NAME != 'PRIMARY'");

    if (!$query->num_rows) {

        // Ensure the warehouse table exists and contains the warehouse_id column
        $this->db->query("ALTER TABLE `" . DB_PREFIX . "product`
            ADD CONSTRAINT `fk_warehouse`
            FOREIGN KEY (`warehouse_id`) REFERENCES `" . DB_PREFIX . "warehouse`(`warehouse_id`)
            ON DELETE CASCADE ON UPDATE CASCADE");

    }

}

